   598→        `  do script "cd '${safeCwd}' && claude '${safePrompt}'"`,
   599→        `end tell`,
   600→      ].join("\n");
   601→      execSync(`osascript -e '${script.replace(/'/g, "'\\''")}'`);
   602→      // Mark selected open items as in_progress
   603→      if (openItemIds?.length) {
