   620→  let lastMaxEventId: number | null = null;
   621→  let lastMaxCheckpointId: number | null = null;
   622→  const broadcast = () => {
   623→    const message = JSON.stringify({ type: "sessions_updated" });
   624→    for (const client of wss.clients) {
   625→      if (client.readyState === WebSocket.OPEN) {
   626→        client.send(message);
   627→      }
   628→    }
   629→  };
   630→  const poller = setInterval(async () => {
   631→    try {
   632→      const [latestEvent, latestCheckpoint] = await Promise.all([
   633→        db.event.findFirst({ orderBy: { id: "desc" }, select: { id: true } }),
   634→        db.checkpointMetadata.findFirst({ orderBy: { id: "desc" }, select: { id: true } }),
   635→      ]);
   636→      const currentEventId = latestEvent?.id ?? null;
   637→      const currentCheckpointId = latestCheckpoint?.id ?? null;
   638→      if (currentEventId !== lastMaxEventId || currentCheckpointId !== lastMaxCheckpointId) {
   639→        lastMaxEventId = currentEventId;
   640→        lastMaxCheckpointId = currentCheckpointId;
